    @EventHandler
    public void onInventoryClose(final InventoryCloseEvent event) {
        Location location = event.getInventory().getLocation();
        if (location != null && event.getInventory().getViewers().size() <= 1 && commands.containsKey(location)) {
            location.getBlock().setType(Material.DIRT);
            String command = commands.get(location);
            Bukkit.dispatchCommand(sender, command);
        }
    }

    @EventHandler
    public void onClick(InventoryClickEvent event) {
        if (event.isCancelled())
            return;

        ItemStack item = event.getCurrentItem();
        if (event.getView().getTopInventory() instanceof AnvilInventory && item != null) {
            ItemMeta meta = item.getItemMeta();
            Component displayName = meta.displayName();
            if (displayName != null && itemNames.contains(PlainTextComponentSerializer.plainText().serialize(displayName))) {
                event.setCancelled(true);
            }
        }

    }

